// useFormStatus でペンディング状態
'use client';
import { useFormStatus } from 'react-dom';
function SubmitButton() {
    const { pending } = useFormStatus();
    return <button disabled={pending}>{pending ? '送信中...' : '投稿する'}</button>;
}
